arguments.file_text:
@* Sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <li class="sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span>@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    min-height: 100%;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.sidebar-nav {
    list-style: none;
    padding: 0.5rem 0;
    margin: 0;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    color: #495057;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-item:hover {
    background: #e9ecef;
}

.sidebar-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@* Profile editing section *@

<div class="profile-section">
    <h4>Profile</h4>
    <p class="text-muted">Manage your personal information.</p>

    <div class="avatar-area">
        <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
        <span class="avatar-url text-muted">@_avatarUrl</span>
    </div>

    <div class="form-group">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="_displayName" />
    </div>

    <div class="form-group">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="_email" />
    </div>

    <div class="form-group">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="3" @bind="_bio"></textarea>
    </div>

    <div class="button-row">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;

    protected override void OnParametersSet()
    {
        ResetToProfile();
    }

    private void ResetToProfile()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task Save()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await OnSave.InvokeAsync(updated);
        _saving = false;
    }

    private void Discard() => ResetToProfile();
}

.profile-section {
    max-width: 600px;
}

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

.avatar-url {
    font-size: 0.85rem;
    word-break: break-all;
}

.form-group {
    margin-bottom: 1rem;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

@* Notifications preferences section *@

<div class="notifications-section">
    <h4>Notifications</h4>
    <p class="text-muted">Choose how you want to be notified.</p>

    <div class="toggle-group">
        <div class="toggle-row">
            <div>
                <strong>Email Notifications</strong>
                <div class="text-muted small">Receive notifications via email</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_emailNotifications" />
            </div>
        </div>
        <div class="toggle-row">
            <div>
                <strong>Push Notifications</strong>
                <div class="text-muted small">Receive push notifications in your browser</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_pushNotifications" />
            </div>
        </div>
        <div class="toggle-row">
            <div>
                <strong>Weekly Digest</strong>
                <div class="text-muted small">Get a weekly summary of activity</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_weeklyDigest" />
            </div>
        </div>
    </div>

    <h5 class="mt-4">Muted Channels</h5>
    <p class="text-muted small">Uncheck channels you'd like to mute.</p>
    <div class="channel-list">
        @foreach (var channel in _channels)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="ch-@channel.Name"
                       checked="@(!channel.Muted)"
                       @onchange="() => ToggleChannel(channel)" />
                <label class="form-check-label" for="ch-@channel.Name">
                    #@channel.Name @(channel.Muted ? "(muted)" : "")
                </label>
            </div>
        }
    </div>

    <div class="mt-4">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];
    private bool _saving;

    private record ChannelState(string Name, bool Muted);

    protected override void OnParametersSet()
    {
        _emailNotifications = Prefs.EmailNotifications;
        _pushNotifications = Prefs.PushNotifications;
        _weeklyDigest = Prefs.WeeklyDigest;
        _channels = Prefs.MutedChannels
            .Select(c => new ChannelState(c, true))
            .ToList();
    }

    private void ToggleChannel(ChannelState channel)
    {
        var idx = _channels.IndexOf(channel);
        if (idx >= 0)
            _channels[idx] = channel with { Muted = !channel.Muted };
    }

    private async Task Save()
    {
        _saving = true;
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await OnSave.InvokeAsync(updated);
        _saving = false;
    }
}

.notifications-section {
    max-width: 600px;
}

.toggle-group {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 1.25rem;
    border-bottom: 1px solid #dee2e6;
}

.toggle-row:last-child {
    border-bottom: none;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 8px;
}

@* Expandable change password panel *@

<div class="change-password-panel">
    <button class="panel-header" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="form-group">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="form-group">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _saving;

    private async Task UpdatePassword()
    {
        _error = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _saving = false;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _expanded = false;
    }
}

.change-password-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    margin-bottom: 1.5rem;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 1rem 1.25rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-weight: 600;
    border-radius: 8px;
}

.panel-body {
    padding: 1.25rem;
    border-top: 1px solid #dee2e6;
}

.panel-body .form-group {
    margin-bottom: 1rem;
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

@* Active sessions table with revoke confirmation *@

<div class="sessions-table-wrapper">
    <h5>Active Sessions</h5>
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            @if (_confirmingSessionId == session.Id)
                            {
                                <span class="confirm-group">
                                    <span class="text-danger small">Revoke?</span>
                                    <button class="btn btn-sm btn-danger" @onclick="() => ConfirmRevoke(session.Id)">
                                        Yes
                                    </button>
                                    <button class="btn btn-sm btn-outline-secondary" @onclick="CancelRevoke">
                                        No
                                    </button>
                                </span>
                            }
                            else
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => _confirmingSessionId = session.Id">
                                    Revoke
                                </button>
                            }
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingSessionId;

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmingSessionId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private void CancelRevoke() => _confirmingSessionId = null;

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

