<div class="change-password-panel">
    <button class="panel-header" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="form-group">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="form-group">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _saving;

    private async Task UpdatePassword()
    {
        _error = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _saving = false;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _expanded = false;
    }
}
