{"file_text": "@* Appearance settings with live preview *@

<div class="appearance-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize the look and feel of the application.</p>

    <div class="settings-and-preview">
        <div class="settings-controls">
            <div class="control-group">
                <label class="form-label fw-bold">Theme</label>
                <div class="d-flex gap-3">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                   value="@theme" checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="control-group">
                <label class="form-label fw-bold">Font Size</label>
                <div class="d-flex gap-3">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                   value="@size" checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="fs-@size">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="control-group">
                <label class="form-label fw-bold" for="language-select">Language</label>
                <select class="form-select" id="language-select" @bind="_language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                </select>
            </div>

            <div class="control-group">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <span class="fw-bold">Compact Mode</span>
                        <div class="text-muted small">Reduce spacing between elements</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_compactMode" />
                    </div>
                </div>
            </div>

            <button class="btn btn-primary mt-3" @onclick="Save" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="preview-area @GetPreviewClasses()">
            <div class="preview-label">Preview</div>
            <div class="preview-card">
                <h6>Sample Heading</h6>
                <p>This is how your content will look with the selected appearance settings.</p>
                <button class="btn btn-sm btn-primary">Sample Button</button>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;

    protected override void OnParametersSet()
    {
        _theme = Settings.Theme;
        _fontSize = Settings.FontSize;
        _language = Settings.Language;
        _compactMode = Settings.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{_theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task Save()
    {
        _saving = true;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _saving = false;
    }
}
