toolArgs.file_text:
@* Notifications preferences section *@

<div class="notifications-section">
    <h4>Notifications</h4>
    <p class="text-muted">Choose how you want to be notified.</p>

    <div class="toggle-group">
        <div class="toggle-row">
            <div>
                <strong>Email Notifications</strong>
                <div class="text-muted small">Receive notifications via email</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_emailNotifications" />
            </div>
        </div>
        <div class="toggle-row">
            <div>
                <strong>Push Notifications</strong>
                <div class="text-muted small">Receive push notifications in your browser</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_pushNotifications" />
            </div>
        </div>
        <div class="toggle-row">
            <div>
                <strong>Weekly Digest</strong>
                <div class="text-muted small">Get a weekly summary of activity</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_weeklyDigest" />
            </div>
        </div>
    </div>

    <h5 class="mt-4">Muted Channels</h5>
    <p class="text-muted small">Uncheck channels you'd like to mute.</p>
    <div class="channel-list">
        @foreach (var channel in _channels)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="ch-@channel.Name"
                       checked="@(!channel.Muted)"
                       @onchange="() => ToggleChannel(channel)" />
                <label class="form-check-label" for="ch-@channel.Name">
                    #@channel.Name @(channel.Muted ? "(muted)" : "")
                </label>
            </div>
        }
    </div>

    <div class="mt-4">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];
    private bool _saving;

    private record ChannelState(string Name, bool Muted);

    protected override void OnParametersSet()
    {
        _emailNotifications = Prefs.EmailNotifications;
        _pushNotifications = Prefs.PushNotifications;
        _weeklyDigest = Prefs.WeeklyDigest;
        _channels = Prefs.MutedChannels
            .Select(c => new ChannelState(c, true))
            .ToList();
    }

    private void ToggleChannel(ChannelState channel)
    {
        var idx = _channels.IndexOf(channel);
        if (idx >= 0)
            _channels[idx] = channel with { Muted = !channel.Muted };
    }

    private async Task Save()
    {
        _saving = true;
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await OnSave.InvokeAsync(updated);
        _saving = false;
    }
}

