toolArgs.file_text:
@* Active sessions table with revoke confirmation *@

<div class="sessions-table-wrapper">
    <h5>Active Sessions</h5>
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            @if (_confirmingSessionId == session.Id)
                            {
                                <span class="confirm-group">
                                    <span class="text-danger small">Revoke?</span>
                                    <button class="btn btn-sm btn-danger" @onclick="() => ConfirmRevoke(session.Id)">
                                        Yes
                                    </button>
                                    <button class="btn btn-sm btn-outline-secondary" @onclick="CancelRevoke">
                                        No
                                    </button>
                                </span>
                            }
                            else
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => _confirmingSessionId = session.Id">
                                    Revoke
                                </button>
                            }
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingSessionId;

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmingSessionId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private void CancelRevoke() => _confirmingSessionId = null;

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

