@* Security settings section *@

<div class="security-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security.</p>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="tfa-row">
        <div>
            <strong>Two-Factor Authentication</strong>
            <div class="text-muted small">Add an extra layer of security to your account</div>
        </div>
        <div class="tfa-status">
            <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
            <div class="form-check form-switch ms-2">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@Security.TwoFactorEnabled"
                       @onchange="HandleTwoFactorToggle" />
            </div>
        </div>
    </div>

    @if (Security.LastPasswordChange.HasValue)
    {
        <p class="text-muted small mt-2">
            Last password change: @Security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <ActiveSessionsTable Sessions="Security.Sessions" OnRevoke="OnRevokeSession" />
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter, EditorRequired] public EventCallback<bool> OnToggleTwoFactor { get; set; }

    private async Task HandleTwoFactorToggle(ChangeEventArgs e)
    {
        var enabled = (bool)(e.Value ?? false);
        await OnToggleTwoFactor.InvokeAsync(enabled);
    }
}

.security-section {
    max-width: 700px;
}

.tfa-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 1.25rem;
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 8px;
}

.tfa-status {
    display: flex;
    align-items: center;
}

