arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@inject ISettingsService SettingsService

@* Settings dashboard page — owns all data and orchestrates section rendering *@

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />

    <main class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else
        {
            @if (_toast is not null)
            {
                <div class="toast-message alert @(_toast.IsError ? "alert-danger" : "alert-success") alert-dismissible">
                    @_toast.Message
                    <button type="button" class="btn-close" @onclick="() => _toast = null"></button>
                </div>
            }

            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="_profile!" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="_notificationPrefs!" OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Security="_security!"
                                     OnChangePassword="HandleChangePassword"
                                     OnRevokeSession="HandleRevokeSession"
                                     OnToggleTwoFactor="HandleToggleTwoFactor" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="_appearance!" OnSave="SaveAppearance" />
                    break;
            }
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    private ToastState? _toast;

    private record ToastState(string Message, bool IsError = false);

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
        _security = await SettingsService.GetSecuritySettingsAsync();
        _appearance = await SettingsService.GetAppearanceAsync();
        _loading = false;
    }

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
        ShowToast("Profile saved successfully.");
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
        ShowToast("Notification preferences saved.");
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        try
        {
            await SettingsService.ChangePasswordAsync(args.Current, args.New);
            _security = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to change password: {ex.Message}", isError: true);
        }
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
        ShowToast("Session revoked.");
    }

    private async Task HandleToggleTwoFactor(bool enabled)
    {
        // In a real app this would call a service method
        _security = _security! with { TwoFactorEnabled = enabled };
        ShowToast(enabled ? "Two-factor authentication enabled." : "Two-factor authentication disabled.");
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
        ShowToast("Appearance settings saved.");
    }

    private void ShowToast(string message, bool isError = false)
    {
        _toast = new ToastState(message, isError);
    }
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 60px);
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    margin: 1rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
}

.toast-message {
    position: sticky;
    top: 0;
    z-index: 10;
    margin-bottom: 1rem;
    animation: slideIn 0.3s ease-out;
}

@keyframes slideIn {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

